insert into t_dictionary (id, dic_type_id, dic_type_name, 
  dic_key, dic_value, status
  )
values (#{id,jdbcType=INTEGER}, #{dicTypeId,jdbcType=INTEGER}, #{dicTypeName,jdbcType=VARCHAR}, 
  #{dicKey,jdbcType=VARCHAR}, #{dicValue,jdbcType=VARCHAR}, #{status,jdbcType=INTEGER}
  )

mapper.select:
	select 
	from t_dictionary



        		dic_type_id = #{model.dicTypeId}


        		and dic_type_name like CONCAT("%", #{model.dicTypeName}, "%")


        		and dic_key like CONCAT("%", #{model.dicKey}, "%")


        		and dic_value like CONCAT("%", #{model.dicValue}, "%")


        		and status = #{model.status}



      		and (
      			dic_type_name like CONCAT("%", #{fuzzy}, "%") or
    			dic_key like CONCAT("%", #{fuzzy}, "%") or
      			dic_value like CONCAT("%", #{fuzzy}, "%")
      		)



   		order by ${orderBy}


   		limit #{start} ,#{pageSize}

	select dic_type_id from t_dictionary


      	dic_type_name = #{dicTypeName,jdbcType=VARCHAR}


	limit 1
